mapper.insert:
insert into min30k (code, day, name, open, high, low, trade, last_trade, percent, volume, amount, ma5, ma10, ma20, ma30, ma60, ma120, dea, dif, macd, cross_params, create_time, update_time)
values (#{code}, #{day}, #{name}, #{open}, #{high}, #{low}, #{trade}, #{lastTrade}, #{percent}, #{volume}, #{amount}
  , #{ma5}, #{ma10}, #{ma20}, #{ma30}, #{ma60}, #{ma120}, #{dea}, #{dif}, #{macd}, #{crossParams}, now(), now())

mapper.update:
update min30k set update_time = now()

       , name = #{name}


       , open = #{open}


       , high = #{high}


       , low = #{low}


       , trade = #{trade}


       , last_trade = #{lastTrade}


       , percent = #{percent}


       , volume = #{volume}


       , amount = #{amount}


       , ma5 = #{ma5}


       , ma10 = #{ma10}


       , ma20 = #{ma20}


       , ma30 = #{ma30}


       , ma60 = #{ma60}


       , ma120 = #{ma120}


        , dea = #{dea}


        , dif = #{dif}


        , macd = #{macd}


       , cross_params = #{crossParams}

where code = #{code} and day = #{day}

mapper.select:
select w.* from min30k w where
w.code = #{code} and w.day < #{fromMin30}
order by w.day desc limit 1

   	select w.code, w.day, w.open, w.trade, w.last_trade, w.high, w.low, w.ma5, w.ma10, w.ma20, w.ma30, w.ma60, w.ma120, w.dea, w.dif, w.macd
   	 from min30k w  


		  		and w.code = #{code}



				and	(select count(*) from min30k where code=w.code and day > w.day) < #{nmin30s}
